fun solve(c: Long, connections: Array<Array<Long>>, queries: Array<Array<Long>>): Array<Long> {
    val parent = LongArray((c + 1).toInt()) { it.toLong() }
    val rank = IntArray((c + 1).toInt()) { 1 }
    val online = BooleanArray((c + 1).toInt()) { true }

    fun find(u: Long): Long {
        var current = u
        while (parent[current.toInt()] != current) {
            parent[current.toInt()] = parent[parent[current.toInt()].toInt()]
            current = parent[current.toInt()]
        }
        return current
    }

    fun union(u: Long, v: Long) {
        val rootU = find(u)
        val rootV = find(v)
        if (rootU == rootV) return
        if (rank[rootU.toInt()] > rank[rootV.toInt()]) {
            parent[rootV.toInt()] = rootU
            rank[rootU.toInt()] += rank[rootV.toInt()]
        } else {
            parent[rootU.toInt()] = rootV
            rank[rootV.toInt()] += rank[rootU.toInt()]
        }
    }

    for (conn in connections) {
        union(conn[0], conn[1])
    }

    // Initialize min_node for each component
    val minNode = LongArray((c + 1).toInt()) { it.toLong() }
    for (u in 1..c.toInt()) {
        val root = find(u.toLong())
        if (minNode[root.toInt()] > u) {
            minNode[root.toInt()] = u.toLong()
        }
    }

    // To efficiently find the smallest online node in a component, we'll use a TreeSet per component
    val componentSets = mutableMapOf<Long, TreeSet<Long>>()
    for (u in 1..c.toInt()) {
        val root = find(u.toLong())
        componentSets.getOrPut(root) { TreeSet() }.add(u.toLong())
    }

    val result = mutableListOf<Long>()
    for (query in queries) {
        val type = query[0]
        val x = query[1]
        if (type == 1L) {
            if (online[x.toInt()]) {
                result.add(x)
            } else {
                val root = find(x)
                val set = componentSets[root] ?: TreeSet()
                val smallestOnline = set.ceiling(1L)
                if (smallestOnline != null) {
                    result.add(smallestOnline)
                } else {
                    result.add(-1L)
                }
            }
        } else if (type == 2L) {
            online[x.toInt()] = false
            val root = find(x)
            componentSets[root]?.remove(x)
        }
    }

    return result.toTypedArray()
}
